        # CRITICAL: verified_data is the signed content returned by XMLVerifier
        doc, verified_data = self.parse_and_verify_signature(xml_bytes)

        # Step 3: Extract assertion from VERIFIED data only (prevents XSW)
        assertion = self._extract_assertion_from_verified_data(verified_data)

        # Step 4: Validate response-level properties
        self.validate_response_status(doc)
        self.validate_destination(doc)

        # Step 5: Validate assertion properties
        self.validate_issuer(doc, assertion)
        self.validate_conditions(assertion)
        self.validate_subject(assertion)
        self.check_replay(assertion)

        # Step 6: Extract attributes from the verified assertion
        user_attributes = self.extract_user_attributes(assertion)

        if not user_attributes.get('name_id'):
            raise SAMLValidationError("No NameID found in assertion")

        logger.info("SAML assertion successfully validated for user session creation")
        return user_attributes


