def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.before_request
def enforce_https():
    """Enforce HTTPS in production."""
    if not request.is_secure and request.headers.get('X-Forwarded-Proto', 'http') != 'https':
        if not app.debug:
            abort(403, "HTTPS required")


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response


@app.route('/saml/acs', methods=['POST'])
def assertion_consumer_service():
    """
    SAML Assertion Consumer Service (ACS) endpoint.

    Receives SAML responses via HTTP POST binding.
    """
    if saml_processor is None:
        logger.error("SAML processor not initialized")
        abort(500, "SSO service unavailable")

    # Validate content type
    if not request.content_type or 'application/x-www-form-urlencoded' not in request.content_type:
        abort(400, "Invalid content type")

    encoded_response = request.form.get('SAMLResponse')
    if not encoded_response:
        abort(400, "Missing SAMLResponse parameter")

    try:
        user_attributes = saml_processor.process_response(encoded_response)
    except SAMLValidationError as e:
        logger.warning("SAML validation failed: %s", str(e))
        abort(403, "SSO authentication failed")
    except Exception:
        logger.exception("Unexpected error processing SAML response")
        abort(500, "SSO processing error")

    # Create secure session
    session.clear()
    session.permanent = True
    session['user'] = {
        'name_id': user_attributes.get('name_id'),
        'email': user_attributes.get('email', ''),
        'first_name': user_attributes.get('first_name', ''),
        'last_name': user_attributes.get('last_name', ''),
        'display_name': user_attributes.get('display_name', ''),
        'groups': user_attributes.get('groups', []),
        'role': user_attributes.get('role', ''),
    }
    session['authenticated_at'] = datetime.now(timezone.utc).isoformat()
    session['auth_method'] = 'saml_sso'

    # Regenerate session ID to prevent session fixation
    # Flask doesn't have built-in session regeneration, but clearing and recreating helps
    logger.info("User session created via SAML SSO")

    # Handle RelayState for redirect
    relay_state = request.form.get('RelayState', '')
    # Validate RelayState to prevent open redirect
    if relay_state and _is_safe_redirect_url(relay_state):
        return redirect(relay_state)

    return redirect(url_for('dashboard'))


def _is_safe_redirect_url(url: str) -> bool:
    """Validate that a redirect URL is safe (same origin)."""
    from urllib.parse import urlparse
    parsed = urlparse(url)
    # Only allow relative URLs or URLs to our own domain
    if not parsed.netloc:
        # Relative URL - ensure it doesn't start with // (protocol-relative)
        return not url.startswith('//')
    allowed_hosts = {urlparse(SAML_CONFIG['acs_url']).netloc}
    return parsed.netloc in allowed_hosts and parsed.scheme in ('https',)


