@app.route('/dashboard')
@login_required
def dashboard():
    """Protected dashboard page."""
    user = session.get('user', {})
    return jsonify({
        'message': 'Authenticated',
        'user': {
            'name_id': user.get('name_id'),
            'email': user.get('email'),
            'display_name': user.get('display_name'),
        },
        'authenticated_at': session.get('authenticated_at'),
    })


